const CALCULATIONS = [["paese_group","if(${country}='paese_16_1','gaza',if(${country}='paese_16_2','cisgiordania',if(${country}='paese_16_3','cisgiordania',if(${country}='paese_16_4','giordania',if(${country}='paese_16_5','libano',if(${country}='paese_16_6','siria','diaspora'))))))","paese_group"],["file_name","if(${file_type}='tipo_file_19_1',${media_audio},if(${file_type}='tipo_file_19_3',${media_foto},if(${file_type}='tipo_file_19_2',${media_video},${media_documento})))","sez_materiali/file_name"]];
